  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'doc-outline-scroll') {
      var el = document.querySelector('[data-outline-idx="' + e.data.index + '"]');
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  });

